div.script:
document.getElementById('pay-btn').onclick = function(){

    var options = {
        "key": "",
        "amount": "",
        "currency": "INR",
        "name": "Odoo Payment",
        "order_id": "",

        "handler": function (response){
            window.location.href =
            "/razorpay/success?order_id=" + response.razorpay_order_id;
        }
    };

    var rzp = new Razorpay(options);
    rzp.open();
}
